/**
 * Sets the vector to the given components
 *
 * @param x The x-component
 * @param y The y-component
 * @param z The z-component
 * @return this vector for chaining
 */
public Vector3 set(float x, float y, float z) {
    this.x = x;
    this.y = y;
    this.z = z;
    return this;
}
